import streamlit as st
import streamlit.components.v1 as components

st.set_page_config(
    page_title="Wings of Glory Bingo",
    layout="centered",
    initial_sidebar_state="collapsed",
)

st.markdown("""
<style>
header[data-testid="stHeader"] { display: none; }
#MainMenu { visibility: hidden; }
footer { visibility: hidden; }
.block-container { padding: 0 !important; max-width: 100% !important; }
.stApp { background: #070910; }
iframe { display: block; margin: 0 auto; }
</style>
""", unsafe_allow_html=True)

html = "<!doctype html>\n<html>\n<head>\n<meta charset=\"utf-8\">\n<style>\n:root{\n  --bg:#070910;\n  --grid:#4a3510;\n  --cell:#172033;\n  --cell2:#1b2740;\n  --marked:#138a52;\n  --free:#532e86;\n  --gold:#ffd166;\n  --gold2:#ffb703;\n  --red:#ef476f;\n  --blue:#4cc9f0;\n  --green:#06d6a0;\n  --purple:#b517ff;\n  --text:#f8fafc;\n  --muted:#a8b3c7;\n}\n*{box-sizing:border-box}\nhtml,body{\n  margin:0;\n  background:var(--bg);\n  color:var(--text);\n  font-family:\"Segoe UI\",Arial,sans-serif;\n  overflow:hidden;\n}\n.app{\n  width:535px;\n  max-width:100vw;\n  height:620px;\n  max-height:100vh;\n  margin:0 auto;\n  background:var(--bg);\n  display:flex;\n  flex-direction:column;\n  padding:7px 8px 5px;\n}\n.header{\n  display:flex;\n  justify-content:center;\n  align-items:flex-start;\n  gap:8px;\n}\n.dice{\n  width:40px;\n  color:var(--gold);\n  font-size:24px;\n  line-height:28px;\n  text-align:center;\n}\n.title-area{text-align:center}\n.title{\n  color:var(--gold);\n  font-size:18px;\n  line-height:22px;\n  font-weight:700;\n}\n.subtitle{\n  color:var(--muted);\n  font-size:11px;\n  line-height:14px;\n  font-weight:700;\n}\n.controls{\n  display:flex;\n  justify-content:center;\n  gap:4px;\n  margin:4px 0;\n}\nbutton{\n  border:none;\n  background:#251a08;\n  color:var(--gold);\n  font-size:8px;\n  font-weight:700;\n  height:24px;\n  padding:4px 8px;\n  cursor:pointer;\n  font-family:\"Segoe UI\",Arial,sans-serif;\n}\nbutton:hover{background:#4a320b;color:#fff4c7}\n.neon{\n  height:2px;\n  margin:0 36px 4px;\n  background:var(--purple);\n}\n.outer{\n  background:var(--gold2);\n  margin:6px 8px;\n  flex:1;\n  min-height:0;\n  display:flex;\n}\n.inner{\n  background:#2b210e;\n  margin:2px;\n  flex:1;\n  min-height:0;\n  display:flex;\n}\n.board{\n  background:var(--grid);\n  margin:2px;\n  flex:1;\n  min-height:0;\n  display:grid;\n  grid-template-columns:repeat(5,1fr);\n  grid-template-rows:repeat(5,1fr);\n}\n.cell{\n  margin:1px;\n  background:var(--cell);\n  color:var(--text);\n  display:flex;\n  align-items:center;\n  justify-content:center;\n  text-align:center;\n  white-space:pre-line;\n  overflow:hidden;\n  padding:2px;\n  font-size:8px;\n  line-height:1.12;\n  font-weight:700;\n  cursor:pointer;\n  user-select:none;\n}\n.cell.alt{background:var(--cell2)}\n.cell:hover:not(.free){background:#263554}\n.cell.free{\n  background:var(--free)!important;\n  color:var(--gold);\n  font-size:11px;\n  font-style:italic;\n  cursor:default;\n}\n.cell.marked{\n  background:var(--marked)!important;\n  color:#ecfff4;\n}\n.cell.pulse0{background:#2ee88e!important;color:#ecfff4}\n.cell.pulse1{background:#20b875!important;color:#ecfff4}\n.status{\n  color:var(--muted);\n  font-size:8px;\n  text-align:center;\n  padding-bottom:5px;\n}\n.overlay{\n  position:fixed;\n  inset:0;\n  display:none;\n  background:#000;\n  z-index:20;\n  align-items:center;\n  justify-content:center;\n  text-align:center;\n}\n.overlay.show{display:flex}\n.big{\n  color:var(--gold);\n  font-size:56px;\n  font-weight:700;\n  animation:pulse .55s ease-in-out infinite alternate;\n}\n@keyframes pulse{\n  from{transform:scale(.95)}\n  to{transform:scale(1.12);filter:brightness(1.25)}\n}\n.sub{\n  color:#fff;\n  font-size:15px;\n  font-weight:700;\n  margin-top:10px;\n}\n.hint{\n  color:var(--muted);\n  font-size:9px;\n  margin-top:16px;\n}\n.star{\n  position:fixed;\n  z-index:30;\n  pointer-events:none;\n  animation:star .55s ease forwards;\n}\n@keyframes star{\n  from{opacity:1;transform:scale(.6) rotate(0deg)}\n  to{opacity:0;transform:scale(1.7) rotate(100deg)}\n}\n</style>\n</head>\n<body>\n<div class=\"app\">\n  <div class=\"header\">\n    <div class=\"dice\" id=\"leftDice\">&#9860;</div>\n    <div class=\"title-area\">\n      <div class=\"title\">&#10022; Wings of Glory &#10022;</div>\n      <div class=\"subtitle\">LOW RANK BINGO</div>\n    </div>\n    <div class=\"dice\" id=\"rightDice\">&#9858;</div>\n  </div>\n\n  <div class=\"controls\">\n    <button onclick=\"rollBoard()\">Roll</button>\n    <button onclick=\"resetMarks()\">Reset</button>\n    <button onclick=\"showRules()\">Bingo?</button>\n  </div>\n\n  <div class=\"neon\" id=\"neon\"></div>\n\n  <div class=\"outer\">\n    <div class=\"inner\">\n      <div class=\"board\" id=\"board\"></div>\n    </div>\n  </div>\n\n  <div class=\"status\" id=\"status\">Roll, mark squares, chase bingo.</div>\n</div>\n\n<div class=\"overlay\" id=\"rules\" onclick=\"hideRules()\">\n  <div>\n    <div class=\"big\" style=\"font-size:42px;\">RULES</div>\n    <div class=\"sub\">Click squares &middot; FREE SPACE marked &middot; 5 in a row wins</div>\n    <div class=\"hint\">click anywhere to close</div>\n  </div>\n</div>\n\n<div class=\"overlay\" id=\"bingo\" onclick=\"hideBingo()\">\n  <div>\n    <div class=\"big\" id=\"bingoText\">BINGO!</div>\n    <div class=\"sub\">JACKPOT HIT</div>\n    <div class=\"hint\">click anywhere to close</div>\n  </div>\n</div>\n\n<script>\nconst ITEMS = [\"\\\"add 5th gen aircrafts!\\\"\", \"DOGSHIT opinion or suggestion\", \"corny ass profile/pfp\", \"\\\"errrmm is all bvr so it's LAME\\\"\", \"chaff = flare\", \"thinks they're good\", \"nerf f14a or phoenix missiles\", \"compares wog to wt\", \"doesn't know any bfm/acm\", \"\\\"codes?\\\"\", \"add their favorite niche aircraft\", \"\\\"i have a life/whats wrong with low rank\\\"\", \"realized they have no image perms\", \"\\\"My rank ingame is higher\\\"\", \"extremely biased\", \"intentional rule breaking\", \"\\\"when update?\\\" bro the update is soon chilllll\", \"bitching about killstealing\", \"\\\"(decent plane) is so bad\\\"\", \"\\\"(premium plane) is p2w...\\\"\", \"\\\"add (insert nation) tree!\\\"\", \"can't lose their argument\", \"rants about russian aircrafts\", \"huge fuckass ego\"];\n\nlet board = [];\nlet marked = new Set([12]);\nlet rolling = false;\nconst dice = [9856,9857,9858,9859,9860,9861];\nconst colors = [\"#ffd166\", \"#4cc9f0\", \"#ef476f\", \"#06d6a0\", \"#ffffff\"];\nconst stars = [10022,10023,9733,9670,9679];\n\nfunction chr(n){ return String.fromCodePoint(n); }\n\nfunction pick(a){\n  return a[Math.floor(Math.random() * a.length)];\n}\n\nfunction shuffle(a){\n  let x = a.slice();\n  for(let i=x.length-1;i>0;i--){\n    let j = Math.floor(Math.random() * (i+1));\n    let t=x[i]; x[i]=x[j]; x[j]=t;\n  }\n  return x;\n}\n\nfunction makeBoard(){\n  let list = shuffle(ITEMS);\n  let out = [];\n  let p = 0;\n  for(let i=0;i<25;i++){\n    out.push(i === 12 ? \"FREE SPACE\" : list[p++]);\n  }\n  return out;\n}\n\nfunction wrapText(t){\n  if(t === \"FREE SPACE\") return \"FREE\\nSPACE\";\n  let words = t.split(\" \");\n  let lines = [];\n  let line = \"\";\n  for(let w of words){\n    if(!line) line = w;\n    else if((line + \" \" + w).length <= 13) line += \" \" + w;\n    else{\n      lines.push(line);\n      line = w;\n    }\n  }\n  if(line) lines.push(line);\n  return lines.join(\"\\n\");\n}\n\nfunction render(){\n  let root = document.getElementById(\"board\");\n  root.innerHTML = \"\";\n  for(let i=0;i<25;i++){\n    let c = document.createElement(\"div\");\n    let r = Math.floor(i/5);\n    let col = i % 5;\n    c.className = \"cell\";\n    if((r+col)%2 === 1) c.classList.add(\"alt\");\n    if(i === 12) c.classList.add(\"free\");\n    if(marked.has(i)) c.classList.add(\"marked\");\n    c.dataset.i = i;\n    c.textContent = wrapText(board[i]);\n    c.onclick = function(){ toggleCell(i); };\n    root.appendChild(c);\n  }\n}\n\nfunction cell(i){\n  return document.querySelector('[data-i=\"' + i + '\"]');\n}\n\nfunction resetBoard(){\n  board = makeBoard();\n  marked = new Set([12]);\n  render();\n}\n\nfunction toggleCell(i){\n  if(i === 12 || rolling) return;\n\n  let c = cell(i);\n  if(marked.has(i)){\n    marked.delete(i);\n    c.classList.remove(\"marked\", \"pulse0\", \"pulse1\");\n  }else{\n    marked.add(i);\n    pulse(c,0);\n  }\n\n  if(hasBingo()) showBingo();\n}\n\nfunction pulse(c, step){\n  c.classList.remove(\"marked\", \"pulse0\", \"pulse1\");\n  if(step === 0) c.classList.add(\"pulse0\");\n  if(step === 1) c.classList.add(\"pulse1\");\n  if(step === 2) c.classList.add(\"marked\");\n  if(step < 2) setTimeout(function(){ pulse(c, step+1); }, 70);\n}\n\nfunction rollBoard(){\n  if(rolling) return;\n  rolling = true;\n  document.getElementById(\"status\").textContent = \"Rolling...\";\n\n  let finalBoard = makeBoard();\n  let step = 0;\n\n  function spin(){\n    let temp = makeBoard();\n\n    for(let i=0;i<25;i++){\n      let c = cell(i);\n      if(!c) continue;\n\n      if(i === 12){\n        c.className = \"cell free marked\";\n        c.textContent = \"FREE\\nSPACE\";\n      }else{\n        let r = Math.floor(i/5);\n        let col = i % 5;\n        c.className = \"cell\";\n        if((r+col)%2 === 1) c.classList.add(\"alt\");\n        c.textContent = wrapText(temp[i]);\n        c.style.background = pick([\"#172033\", \"#1b2740\", \"#2a1f3d\", \"#263554\"]);\n        c.style.color = pick([\"#f8fafc\", \"#ffd166\", \"#4cc9f0\"]);\n      }\n    }\n\n    document.getElementById(\"leftDice\").textContent = chr(pick(dice));\n    document.getElementById(\"rightDice\").textContent = chr(pick(dice));\n\n    if(step < 14){\n      step++;\n      setTimeout(spin, 30 + step * 6);\n    }else{\n      board = finalBoard;\n      marked = new Set([12]);\n      rolling = false;\n      document.querySelectorAll(\".cell\").forEach(function(c){\n        c.style.background = \"\";\n        c.style.color = \"\";\n      });\n      render();\n      document.getElementById(\"status\").textContent = \"Rolled. Click squares to mark.\";\n    }\n  }\n\n  spin();\n}\n\nfunction resetMarks(){\n  marked = new Set([12]);\n  render();\n  document.getElementById(\"status\").textContent = \"Marks reset.\";\n}\n\nfunction lines(){\n  let out = [];\n  for(let r=0;r<5;r++) out.push([0,1,2,3,4].map(function(c){ return r*5+c; }));\n  for(let c=0;c<5;c++) out.push([0,1,2,3,4].map(function(r){ return r*5+c; }));\n  out.push([0,6,12,18,24]);\n  out.push([4,8,12,16,20]);\n  return out;\n}\n\nfunction hasBingo(){\n  return lines().some(function(line){\n    return line.every(function(i){ return marked.has(i); });\n  });\n}\n\nfunction showBingo(){\n  document.getElementById(\"bingo\").classList.add(\"show\");\n  bingoAnim(0);\n}\n\nfunction hideBingo(){\n  document.getElementById(\"bingo\").classList.remove(\"show\");\n}\n\nfunction bingoAnim(step){\n  let layer = document.getElementById(\"bingo\");\n  if(!layer.classList.contains(\"show\")) return;\n\n  let text = document.getElementById(\"bingoText\");\n  text.style.color = pick(colors);\n  text.style.fontSize = pick([\"50px\",\"56px\",\"62px\",\"58px\"]);\n\n  for(let i=0;i<5;i++){\n    let s = document.createElement(\"div\");\n    s.className = \"star\";\n    s.textContent = chr(pick(stars));\n    s.style.left = (Math.random()*100) + \"vw\";\n    s.style.top = (Math.random()*100) + \"vh\";\n    s.style.fontSize = (10 + Math.random()*12) + \"px\";\n    s.style.color = pick(colors);\n    document.body.appendChild(s);\n    setTimeout(function(){ s.remove(); }, 560);\n  }\n\n  if(step < 28) setTimeout(function(){ bingoAnim(step+1); }, 90);\n  else{\n    text.style.color = \"#ffd166\";\n    text.style.fontSize = \"56px\";\n  }\n}\n\nfunction showRules(){ document.getElementById(\"rules\").classList.add(\"show\"); }\nfunction hideRules(){ document.getElementById(\"rules\").classList.remove(\"show\"); }\n\ndocument.addEventListener(\"keydown\", function(e){\n  if(e.key === \"Escape\"){\n    hideBingo();\n    hideRules();\n  }\n});\n\nresetBoard();\n</script>\n</body>\n</html>\n"

components.html(html, height=620, scrolling=False)
